import{_ as t,o as e,c as a,a4 as o}from"./chunks/framework.BMymQDdR.js";const m=JSON.parse('{"title":"项目管理","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Project-Management.md","filePath":"zh/v3/designer/Project-Management.md","lastUpdated":1780630099000}'),d={name:"v3/designer/Project-Management.md"},r=o('<h1 id="项目管理" tabindex="-1">项目管理 <a class="header-anchor" href="#项目管理" aria-label="Permalink to &quot;项目管理&quot;">​</a></h1><p>ENERGY Designer 使用 <code>.egp</code> 文件作为项目配置文件，存储在项目根目录。项目管理涵盖创建、打开、加载和历史记录等功能。</p><h2 id="新建项目" tabindex="-1">新建项目 <a class="header-anchor" href="#新建项目" aria-label="Permalink to &quot;新建项目&quot;">​</a></h2><p>通过 <strong>文件 &gt; 新建 &gt; 新建项目</strong>（快捷键 <code>Ctrl+P</code> / macOS <code>Cmd+P</code>）打开新建项目对话框。</p><h3 id="配置项" tabindex="-1">配置项 <a class="header-anchor" href="#配置项" aria-label="Permalink to &quot;配置项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>输入类型</th><th>默认值/提示</th></tr></thead><tbody><tr><td>项目名称</td><td>应用的名称，用于生成项目名和配置</td><td>文本输入</td><td>-</td></tr><tr><td>项目路径</td><td>项目存放的根目录</td><td>文本输入 + 目录选择器</td><td>-</td></tr><tr><td>Go 版本</td><td>系统中检测到的 Go 版本</td><td>自动检测</td><td>Go 1.20+ 为必需</td></tr><tr><td>GUI 渲染框架</td><td>选择 UI 渲染引擎</td><td>下拉选择框</td><td>见下方选项表</td></tr></tbody></table><h4 id="gui-渲染框架选项" tabindex="-1">GUI 渲染框架选项 <a class="header-anchor" href="#gui-渲染框架选项" aria-label="Permalink to &quot;GUI 渲染框架选项&quot;">​</a></h4><table tabindex="0"><thead><tr><th>选项值</th><th>说明</th></tr></thead><tbody><tr><td>LCL (Native - Lazarus Component Library)</td><td>原生桌面 UI 控件库，90+ 原生控件，9 个分类</td></tr><tr><td>WV (Web - WebView2, WebKit2)</td><td>基于系统 WebView 组件，支持 Web 内容嵌入</td></tr><tr><td>CEF (Web - Chromium Embedded Framework)</td><td>基于 Chromium 内核，完整 Web 渲染能力</td></tr></tbody></table><h3 id="项目创建过程" tabindex="-1">项目创建过程 <a class="header-anchor" href="#项目创建过程" aria-label="Permalink to &quot;项目创建过程&quot;">​</a></h3><ol><li>填写项目名称和选择项目路径</li><li>选择 GUI 渲染框架</li><li>点击&quot;创建&quot;按钮</li><li>设计器自动完成： <ul><li>创建项目目录结构（<code>app/</code>、<code>layouts/</code>、<code>resources/</code> 等）</li><li>生成 <code>go.mod</code> 和 <code>go.sum</code> 文件及依赖</li><li>生成 <code>main.go</code> 入口文件（根据 GUI 框架选择不同的初始化方式）</li><li>生成窗体列表文件 <code>app/app.go</code>（包含平台特定初始化代码）</li><li>生成 UI 布局文件 <code>layouts/form1.ui</code></li><li>生成用户代码文件 <code>app/form1.go</code></li><li>生成 UI 代码文件 <code>app/form1.ui.go</code></li><li>生成资源文件（图标、平台元数据等）</li></ul></li></ol><h3 id="go-版本检测" tabindex="-1">Go 版本检测 <a class="header-anchor" href="#go-版本检测" aria-label="Permalink to &quot;Go 版本检测&quot;">​</a></h3><p>创建项目时，设计器会自动检测系统中安装的 Go 版本。Go 1.20 或更高版本为必需。</p><h2 id="打开项目" tabindex="-1">打开项目 <a class="header-anchor" href="#打开项目" aria-label="Permalink to &quot;打开项目&quot;">​</a></h2><p>通过以下方式打开已有项目：</p><ul><li><strong>文件 &gt; 打开</strong>（快捷键 <code>Ctrl+O</code> / macOS <code>Cmd+O</code>）</li><li><strong>工具栏</strong> 点击&quot;打开&quot;按钮</li><li><strong>文件 &gt; 历史项目</strong> 直接点击历史记录</li></ul><p>支持打开的文件类型：</p><ul><li><code>.egp</code> - ENERGY Designer 项目文件</li></ul><h2 id="历史项目" tabindex="-1">历史项目 <a class="header-anchor" href="#历史项目" aria-label="Permalink to &quot;历史项目&quot;">​</a></h2><p>设计器自动记录最近打开的项目，通过 <strong>文件 &gt; 历史项目</strong> 菜单可快速访问。点击历史项目路径即可重新打开该项目。</p><h2 id="项目配置文件-egp" tabindex="-1">项目配置文件 (.egp) <a class="header-anchor" href="#项目配置文件-egp" aria-label="Permalink to &quot;项目配置文件 (.egp)&quot;">​</a></h2><p><code>.egp</code> 是 JSON 格式的项目配置文件，包含：</p><ul><li>项目基本信息（名称、版本等）</li><li>窗体信息列表</li><li>应用配置（图标、元数据等）</li><li>构建配置</li></ul><h3 id="窗体信息" tabindex="-1">窗体信息 <a class="header-anchor" href="#窗体信息" aria-label="Permalink to &quot;窗体信息&quot;">​</a></h3><p>每个窗体记录：</p><ul><li>窗体 ID（唯一标识）</li><li>窗体名称</li><li>UI 布局文件路径</li><li>用户代码文件路径</li></ul><h2 id="新建窗体" tabindex="-1">新建窗体 <a class="header-anchor" href="#新建窗体" aria-label="Permalink to &quot;新建窗体&quot;">​</a></h2><p>通过 <strong>文件 &gt; 新建 &gt; 新建窗体</strong>（快捷键 <code>Ctrl+N</code> / macOS <code>Cmd+N</code>）在当前项目中创建新窗体。</p><p>创建新窗体时：</p><ol><li>自动生成唯一窗体名称（如 <code>Form1</code>、<code>Form2</code>）</li><li>创建设计标签页</li><li>生成对应的 UI 布局文件和 Go 代码文件</li><li>添加到项目管理器的组件树中</li></ol><h2 id="关闭窗体" tabindex="-1">关闭窗体 <a class="header-anchor" href="#关闭窗体" aria-label="Permalink to &quot;关闭窗体&quot;">​</a></h2><p>在设计器标签页上点击窗体标签的关闭按钮可关闭窗体。关闭后窗体从设计器中移除，但仍保留在项目中可重新打开并设计。</p><h2 id="保存" tabindex="-1">保存 <a class="header-anchor" href="#保存" aria-label="Permalink to &quot;保存&quot;">​</a></h2><p>设计器支持<strong>实时自动保存</strong>：UI 设计时属性变更会自动同步到 UI 布局文件。</p><p>手动保存通过 <strong>文件 &gt; 保存</strong>（快捷键 <code>Ctrl+S</code> / macOS <code>Cmd+S</code>）执行。</p>',34),l=[r];function i(c,n,h,s,p,u){return e(),a("div",null,l)}const b=t(d,[["render",i]]);export{m as __pageData,b as default};
